import{_ as s,c as i,a,o as t}from"./app-CEcM0piI.js";const n={};function r(d,e){return t(),i("div",null,e[0]||(e[0]=[a('<p>在docker容器内模拟了虚拟的运行环境,但这个环境只包括了当前容器运行最小的环境,也就是与让当前容器运行无关的命令都不提供</p><p>数据卷（volume）是一个虚拟目录，是容器内目录与宿主机目录之间映射的桥梁。</p><p>容器内运行环境不够用的问题,可以使用数据卷解决</p><p>在数据卷中配置文件与容器虚拟环境的映射,将容器内的文件系统与宿主机内的docker的文件系统双向绑定,其中一个修改另一个也会修改,这样可以使用宿主机的运行环境操作映射的文件 ![[Pasted image 20250110115248.png]]</p><h3 id="命令" tabindex="-1"><a class="header-anchor" href="#命令"><span>命令</span></a></h3><p><strong>创建数据卷</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>docker volume create</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>查看所有数据卷</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>docker volume ls</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>删除指定数据卷</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>docker volume rm 数据卷名</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>查看某个数据卷的详情</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>docker volume inspect 数据卷名</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>清除未使用的数据卷</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>docker volume prune</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="匿名卷" tabindex="-1"><a class="header-anchor" href="#匿名卷"><span>匿名卷</span></a></h2><p>如果下载一个数据库容器,如mysql,没有手动配置数据卷 可以查看一些mysql的数据卷详情,发现mysql有配置数据卷,且名字并不是mysql而是随机生成的字符 这是因为对于这些容器来说,如果不做配置数据卷,那么数据就会存储到容器中,出于数据解耦的目的便做了数据卷,将数据放在宿主机内 当删除了mysql容器后,其保存在宿主机内的数据并没有删除,数据卷也没有删除,但再次下载mysql容器后会生成新的数据卷就无法访问旧数据了</p><p>所以不推荐使用匿名卷</p><p>对于旧的数据可以使用指定目录挂载,将旧的目录挂载到新的数据卷中实现数据迁移</p><p><strong>目录挂载</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>docker run -v 本地目录:容器内目录</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>本地目录必须以“/”或“./”开头的绝对路径，如果直接以名称开头，会被识别为数据卷而非本地目录 -v mysql:/var/lib/mysql 会被识别为一个数据卷叫mysql -v ./mysql:/var/lib/mysql 会被识别为当前目录下的mysql目录</p>',22)]))}const h=s(n,[["render",r]]),c=JSON.parse('{"path":"/tools/docker/2/","title":"2 数据卷","lang":"zh-CN","frontmatter":{"title":"2 数据卷","createTime":"2025/06/18 21:07:44","tags":["工具"],"permalink":"/tools/docker/2/"},"readingTime":{"minutes":1.93,"words":578},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/工具/docker/2 数据卷.md","headers":[]}');export{h as comp,c as data};
